export interface Caption {
  start: number;
  end: number;
  text: string;
}

export function parseCaptions(raw: string): Caption[] {
  const captions: Caption[] = [];
  const regex = /\((\d+):(\d+)\)/g;
  let match;
  const matches: { time: number; index: number; length: number }[] = [];

  while ((match = regex.exec(raw)) !== null) {
    const min = parseInt(match[1], 10);
    const sec = parseInt(match[2], 10);
    const time = min * 60 + sec;
    matches.push({ time, index: match.index, length: match[0].length });
  }

  for (let i = 0; i < matches.length; i++) {
    const current = matches[i];
    const textStart = current.index + current.length;
    const textEnd = (i + 1 < matches.length) ? matches[i + 1].index : raw.length;
    const text = raw.substring(textStart, textEnd).trim().replace(/\\s+/g, " ");

    let end = (i + 1 < matches.length) ? matches[i + 1].time : current.time + 12;
    if (end > current.time + 12 && i + 1 < matches.length) {
      end = current.time + 12;
    }

    if (text) {
      captions.push({
        start: current.time,
        end: i + 1 < matches.length ? end : 1000,
        text
      });
    }
  }

  return captions;
}

