export function getCaptionsForAudio2(audioUrl: string): Caption[] {
  if (audioUrl.includes("hlboo7u3.mp3")) return parseCaptions(RAW_CAPTIONS_hlboo7u3);
  if (audioUrl.includes("5iw1cntr.mp3")) return parseCaptions(RAW_CAPTIONS_5iw1cntr);
  if (audioUrl.includes("3es4cath.mp3")) return parseCaptions(RAW_CAPTIONS_3es4cath);
  if (audioUrl.includes("gclzuxeh.mp3")) return parseCaptions(RAW_CAPTIONS_gclzuxeh);
  if (audioUrl.includes("tu9b2swd.mp3")) return parseCaptions(RAW_CAPTIONS_tu9b2swd);
  if (audioUrl.includes("fplauj94.mp3")) return parseCaptions(RAW_CAPTIONS_fplauj94);
  return CAPTIONS2;
}
